modules.fpm_unpack:
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);

    // Unpack channel A
    wire a_sign_bit = a[31];
    wire [7:0] a_exp_bits = a[30:23];
    wire [22:0] a_mant_bits = a[22:0];

    // For normalized numbers (exp != 0), add implicit leading 1
    // For denormals (exp == 0), no implicit 1
    wire [23:0] a_mant_with_implicit = (a_exp_bits == 8'b0) ? 
                                        {1'b0, a_mant_bits} : 
                                        {1'b1, a_mant_bits};

    // Detect special cases for A
    wire a_is_zero_internal = (a_exp_bits == 8'b0) && (a_mant_bits == 23'b0);
    wire a_is_inf_internal = (a_exp_bits == 8'hFF) && (a_mant_bits == 23'b0);
    wire a_is_nan_internal = (a_exp_bits == 8'hFF) && (a_mant_bits != 23'b0);

    // Unpack channel B
    wire b_sign_bit = b[31];
    wire [7:0] b_exp_bits = b[30:23];
    wire [22:0] b_mant_bits = b[22:0];

    // For normalized numbers (exp != 0), add implicit leading 1
    // For denormals (exp == 0), no implicit 1
    wire [23:0] b_mant_with_implicit = (b_exp_bits == 8'b0) ? 
                                        {1'b0, b_mant_bits} : 
                                        {1'b1, b_mant_bits};

    // Detect special cases for B
    wire b_is_zero_internal = (b_exp_bits == 8'b0) && (b_mant_bits == 23'b0);
    wire b_is_inf_internal = (b_exp_bits == 8'hFF) && (b_mant_bits == 23'b0);
    wire b_is_nan_internal = (b_exp_bits == 8'hFF) && (b_mant_bits != 23'b0);

    // Assign outputs for channel A
    assign a_sign = a_sign_bit;
    assign a_exp = a_exp_bits;
    assign a_mant = a_mant_with_implicit;
    assign a_is_nan = a_is_nan_internal;
    assign a_is_inf = a_is_inf_internal;
    assign a_is_zero = a_is_zero_internal;

    // Assign outputs for channel B
    assign b_sign = b_sign_bit;
    assign b_exp = b_exp_bits;
    assign b_mant = b_mant_with_implicit;
    assign b_is_nan = b_is_nan_internal;
    assign b_is_inf = b_is_inf_internal;
    assign b_is_zero = b_is_zero_internal;

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    // Sign is XOR of input signs
    assign result_sign = a_sign ^ b_sign;

    // Product is multiplication of mantissas (24-bit × 24-bit = 48-bit)
    assign product = a_mant * b_mant;

    // Raw exponent is sum of exponents minus the bias (127)
    // Using 10 bits to handle intermediate sum (8+8=16 bits, minus 7 bits bias = 9 bits, but need headroom)
    assign raw_exp = a_exp + b_exp - 10'd127;
endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    assign norm_frac = 0;
    assign norm_exp  = 0;
    assign guard     = 0;
    assign sticky    = 0;
endmodule

modules.fpm_round_pack:
`timescale 1ns/1ps
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);
    wire [22:0] rounded_frac;
    wire [9:0]  rounded_exp;
    wire        round_up;

    // Determine if we should round up
    // Round to nearest, ties to even:
    // - Round up if guard=1 and (sticky=1 or frac[0]=1)
    assign round_up = guard & (sticky | norm_frac[0]);

    // Add rounding bit to fraction
    wire [23:0] frac_plus_round = {1'b0, norm_frac} + (round_up ? 24'b1 : 24'b0);

    // Check if rounding caused overflow in fraction (fraction became 1.0)
    wire frac_overflow = frac_plus_round[23];

    // If fraction overflowed, increment exponent and clear fraction
    assign rounded_frac = frac_overflow ? 23'b0 : frac_plus_round[22:0];
    assign rounded_exp = frac_overflow ? (norm_exp + 1'b1) : norm_exp;

    always @(*) begin
        overflow = 1'b0;
        underflow = 1'b0;

        // Check for special cases
        if (rounded_exp >= 10'd255) begin
            // Overflow to infinity
            overflow = 1'b1;
            result = {sign, 8'b11111111, 23'b0};
        end
        else if (rounded_exp == 10'b0) begin
            // Underflow to zero
            underflow = 1'b1;
            result = {sign, 31'b0};
        end
        else begin
            // Normal case: pack into IEEE 754 format
            result = {sign, rounded_exp[7:0], rounded_frac};
        end
    end
endmodule

modules.fpm_special:
`timescale 1ns/1ps
module fpm_special(
    input         a_is_nan,
    input         a_is_inf,
    input         a_is_zero,
    input         b_is_nan,
    input         b_is_inf,
    input         b_is_zero,
    input         result_sign,
    output        is_special,
    output reg [31:0] special_result
);

    wire is_nan;
    wire is_inf_times_zero;
    wire is_inf;
    wire is_zero;

    // NaN if either operand is NaN
    assign is_nan = a_is_nan | b_is_nan;

    // Inf × 0 or 0 × Inf produces NaN
    assign is_inf_times_zero = (a_is_inf & b_is_zero) | (a_is_zero & b_is_inf);

    // Infinity result (but not if it's inf*0 which is NaN)
    assign is_inf = (a_is_inf | b_is_inf) & ~is_inf_times_zero;

    // Zero result (but not if it involves inf*0 which is NaN)
    assign is_zero = (a_is_zero | b_is_zero) & ~is_inf_times_zero;

    // Special case if any of the above apply
    assign is_special = is_nan | is_inf_times_zero | is_inf | is_zero;

    always @(*) begin
        if (is_nan | is_inf_times_zero) begin
            // NaN: 0x7FC00000 (quiet NaN with sign bit 0)
            special_result = 32'h7FC00000;
        end
        else if (is_inf) begin
            // Infinity: sign bit determines +Inf or -Inf
            special_result = {result_sign, 31'h7F800000};
        end
        else if (is_zero) begin
            // Zero: sign bit determines +0 or -0
            special_result = {result_sign, 31'h00000000};
        end
        else begin
            special_result = 32'h00000000;
        end
    end

endmodule
